import json
from dataclasses import dataclass, fields


@dataclass(frozen=True)
class Config:
    """Typed, immutable report configuration."""

    title: str = "Report"
    output_format: str = "text"  # "text" or "markdown"
    max_rows: int = 10
    include_summary: bool = True


def load_config(path):
    """Load config from a JSON file, filling in defaults for missing keys.

    Raises ValueError if the JSON contains an unknown setting.
    """
    with open(path) as f:
        raw = json.load(f)
    known = {f.name for f in fields(Config)}
    unknown = set(raw) - known
    if unknown:
        raise ValueError(
            "Unknown config key(s): " + ", ".join(sorted(unknown))
        )
    return Config(**raw)

